import React, { useState, useEffect } from "react";
import api from './api';

export default function NewFeed() {
  const [toast, setToast] = useState(null);

  const [commentsMap, setCommentsMap] = useState({});
  const [commentInputs, setCommentInputs] = useState({});
  const [posts, setPosts] = useState([]);
  const [currentUserId, setCurrentUserId] = useState(null);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  useEffect(() => {
    try {
      const token = localStorage.getItem('token');
      if (token) {
        const payload = JSON.parse(atob(token.split('.')[1]));
        setCurrentUserId(payload.id);
      }
    } catch (err) { }
    api.fetchPosts().then(async (data) => {
      const postsData = data.posts || [];
      setPosts(postsData);
      // fetch comments for each post and initialize maps
      postsData.forEach(async (p) => {
        try {
          const res = await api.fetchComments(p.id);
          setCommentsMap(prev => ({ ...prev, [p.id]: res.comments || [] }));
        } catch (err) { console.error('Error fetching comments for post', p.id, err); }
      });
    }).catch(console.error);
  }, []);

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Nội dung chính */}
      <div className="flex-1 ml-[72px] flex flex-col">
        {/* --- Header đã bị loại bỏ --- */}

        {/* Feed hiển thị bài đăng */}
        <div className="flex flex-col items-center gap-4 mt-[20px] w-full">
          {/* Toast */}
          {toast && (
            <div className="fixed top-[40px] right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
              {toast}
            </div>
          )}

          {/* Danh sách bài post */}
          {posts.length === 0 && (
            <div className="text-gray-500">Chưa có bài viết</div>
          )}
          {posts.map((p, i) => (
              <div key={p.id || i} className="flex flex-col bg-[#A2D3FF] w-full max-w-[1000px] p-4 rounded-[5px] gap-6">
              {/* Header bài post */}
              <div className="flex items-center gap-4">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/t3jnx5iy_expires_30_days.png"
                  alt="avatar"
                  className="w-[58px] h-[51px]"
                />
                <div className="flex flex-col">
                  <span className="text-black text-xl">{p?.author || p?.display_name || 'Người dùng'}</span>
                  <span className="text-black text-base">{new Date(p.created_at).toLocaleString()}</span>
                </div>
              </div>

              {/* Ảnh bài đăng */}
              {p.images && p.images.length > 0 ? (
                <img src={p.images[0]} alt="post" className="rounded-lg w-full" />
              ) : (
                <img src={"https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/t3jnx5iy_expires_30_days.png"} alt="placeholder" className="rounded-lg w-full" />
              )}

              {/* Khu vực bình luận */}
              <div className="flex items-center gap-2 mt-2">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/v4rj7jgu_expires_30_days.png"
                  alt="like"
                  className="w-[39px] h-[45px] cursor-pointer hover:scale-110 transition-transform"
                  onClick={() => {
                    api.likePost(p.id).then(() => showToast('Bạn đã thả tim ❤️')).catch(console.error);
                  }}
                />
                <input
                  placeholder="Bình luận..."
                  value={commentInputs[p.id] || ''}
                  onChange={(e) => setCommentInputs(prev => ({ ...prev, [p.id]: e.target.value }))}
                  className="flex-1 py-2 px-4 rounded-lg text-black border-0"
                />
                <button
                  className="bg-blue-500 text-white px-3 py-1 rounded-lg"
                  onClick={() => {
                    const content = (commentInputs[p.id] || '').trim();
                    if (!content) return;
                    api.createComment({ post_id: p.id, content })
                      .then((resp) => {
                        if (resp.comment) {
                          setCommentsMap(prev => ({ ...prev, [p.id]: [...(prev[p.id] || []), resp.comment] }));
                          setCommentInputs(prev => ({ ...prev, [p.id]: '' }));
                          showToast('Đã gửi bình luận');
                        }
                      })
                      .catch(console.error);
                  }}
                >
                  Gửi
                </button>
              </div>

              {/* Danh sách bình luận */}
              {commentsMap[p.id]?.length > 0 && (
                <div className="mt-2 ml-12 flex flex-col gap-1">
                  {commentsMap[p.id].map((cmt, idx) => {
                    return (
                      <span key={idx} className="text-black text-sm bg-white px-2 py-1 rounded-lg">
                        {cmt.content || cmt}
                      </span>
                    );
                  })}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-down {
            animation: slideDown 0.3s ease-out;
          }
        `}
      </style>
    </div>
  );
}
